import{_ as a,c as e,o as s,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Расширенная конфигурация: Подробное описание расширенных функций | Antigravity-Manager","description":"Изучите методы расширенной конфигурации Antigravity-Manager. Овладейте функциями планирования аккаунтов, маршрутизации моделей, управления квотами и мониторинга статистики.","frontmatter":{"title":"Расширенная конфигурация: Подробное описание расширенных функций | Antigravity-Manager","order":300,"sidebarTitle":"Обновите систему до производственного уровня","subtitle":"Расширенная конфигурация: Подробное описание расширенных функций","description":"Изучите методы расширенной конфигурации Antigravity-Manager. Овладейте функциями планирования аккаунтов, маршрутизации моделей, управления квотами и мониторинга статистики."},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/advanced/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/advanced/index.md"}'),n={name:"ru/lbjlaq/Antigravity-Manager/advanced/index.md"};function d(i,t,o,l,p,c){return s(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="расширенная-конфигурация" tabindex="-1">Расширенная конфигурация <a class="header-anchor" href="#расширенная-конфигурация" aria-label="Permalink to &quot;Расширенная конфигурация&quot;">​</a></h1><p>В этой главе подробно рассматриваются расширенные функции Antigravity Tools: управление конфигурацией, политики безопасности, планирование аккаунтов, маршрутизация моделей, управление квотами, мониторинг и статистика, а также варианты развертывания на сервере. После изучения этого содержания вы сможете улучшить Antigravity Tools от состояния «работает» до состояния «удобный, стабильный и пригодный для эксплуатации».</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Учебник</th><th>Описание</th></tr></thead><tbody><tr><td><a href="./config/">Полное описание конфигурации</a></td><td>Полные поля AppConfig/ProxyConfig, место сохранения на диск и семантика горячего обновления</td></tr><tr><td><a href="./security/">Безопасность и приватность</a></td><td><code>auth_mode</code>, <code>allow_lan_access</code> и проект базовых требований безопасности</td></tr><tr><td><a href="./scheduling/">Высокодоступное планирование</a></td><td>Ротация, фиксированные аккаунты, липкие сессии и механизм повторных попыток при сбоях</td></tr><tr><td><a href="./model-router/">Маршрутизация моделей</a></td><td>Пользовательские маппинги, приоритеты подстановочных знаков и предустановленные стратегии</td></tr><tr><td><a href="./quota/">Управление квотами</a></td><td>Комбинация Quota Protection + Smart Warmup</td></tr><tr><td><a href="./monitoring/">Proxy Monitor</a></td><td>Журналы запросов, фильтрация, восстановление деталей и экспорт</td></tr><tr><td><a href="./token-stats/">Token Stats</a></td><td>Показатели статистики с точки зрения затрат и интерпретация графиков</td></tr><tr><td><a href="./context-compression/">Стабильность длинных сессий</a></td><td>Сжатие контекста, кеширование подписей и сжатие результатов инструментов</td></tr><tr><td><a href="./system/">Системные возможности</a></td><td>Мультиязычность/темы/обновления/автозапуск при включении/HTTP API Server</td></tr><tr><td><a href="./deployment/">Развертывание на сервере</a></td><td>Выбор между Docker noVNC и Headless Xvfb, эксплуатация</td></tr></tbody></table><h2 id="рекомендации-по-учебному-пути" tabindex="-1">Рекомендации по учебному пути <a class="header-anchor" href="#рекомендации-по-учебному-пути" aria-label="Permalink to &quot;Рекомендации по учебному пути&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Рекомендуемый порядок</p><p>В этой главе много материала, рекомендуется изучать по модулям порциями:</p></div><p><strong>Первый этап: конфигурация и безопасность (обязательно)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Полное описание конфигурации → Безопасность и приватность</span></span>
<span class="line"><span>config                     security</span></span></code></pre></div><p>Сначала ознакомьтесь с системой конфигурации (какие настройки требуют перезапуска, какие обновляются в горячем режиме), затем изучите настройки безопасности (особенно при открытии доступа к локальной сети/общественной сети).</p><p><strong>Второй этап: планирование и маршрутизация (рекомендуется)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Высокодоступное планирование → Маршрутизация моделей</span></span>
<span class="line"><span>scheduling                  model-router</span></span></code></pre></div><p>Научитесь использовать минимальное количество аккаунтов для максимальной стабильности, затем используйте маршрутизацию моделей для экранирования изменений от вышестоящих поставщиков.</p><p><strong>Третий этап: квоты и мониторинг (по необходимости)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Управление квотами → Proxy Monitor → Token Stats</span></span>
<span class="line"><span>quota               monitoring      token-stats</span></span></code></pre></div><p>Предотвратите незаметное исчерпание квот, превратите черный ящик вызовов в наблюдаемую систему, оптимизируйте количественные затраты.</p><p><strong>Четвертый этап: стабильность и развертывание (расширенный уровень)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Стабильность длинных сессий → Системные возможности → Развертывание на сервере</span></span>
<span class="line"><span>context-compression         system            deployment</span></span></code></pre></div><p>Решите скрытые проблемы длинных сессий, сделайте клиент похожим на продукт, затем изучите развертывание на сервере.</p><p><strong>Быстрый выбор</strong>:</p><table tabindex="0"><thead><tr><th>Ваш сценарий</th><th>Рекомендуется сначала прочитать</th></tr></thead><tbody><tr><td>Нестабильная ротация нескольких аккаунтов</td><td><a href="./scheduling/">Высокодоступное планирование</a></td></tr><tr><td>Хотите зафиксировать определенное имя модели</td><td><a href="./model-router/">Маршрутизация моделей</a></td></tr><tr><td>Квоты всегда заканчиваются</td><td><a href="./quota/">Управление квотами</a></td></tr><tr><td>Хотите просмотреть журналы запросов</td><td><a href="./monitoring/">Proxy Monitor</a></td></tr><tr><td>Хотите статистику потребления токенов</td><td><a href="./token-stats/">Token Stats</a></td></tr><tr><td>В длинных диалогах часто возникают ошибки</td><td><a href="./context-compression/">Стабильность длинных сессий</a></td></tr><tr><td>Нужно открыть доступ к локальной сети</td><td><a href="./security/">Безопасность и приватность</a></td></tr><tr><td>Нужно развернуть на сервере</td><td><a href="./deployment/">Развертывание на сервере</a></td></tr></tbody></table><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Перед началом подтвердите</p><ul><li>Завершена глава <a href="./../start/">Быстрый старт</a> (минимум завершены установка, добавление аккаунтов, запуск обратного прокси)</li><li>Завершен доступ хотя бы к одному протоколу из главы <a href="./../platforms/">Платформы и интеграции</a> (например, OpenAI или Anthropic)</li><li>Локальный обратный прокси может нормально отвечать на запросы</li></ul></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы вы можете продолжить изучение:</p><ul><li><a href="./../faq/">Часто задаваемые вопросы</a>: Руководство по устранению неполадок при возникновении проблем 401/404/429/прерывания потока</li><li><a href="./../appendix/">Приложение</a>: Справочные материалы, такие как быстрая таблица конечных точек, модели данных, границы возможностей z.ai</li></ul>`,25)])])}const u=a(n,[["render",d]]);export{g as __pageData,u as default};
